data.content:
Here are the key assertions for your scoring boundary tests:

| Scenario | Assertion |
|----------|-----------|
| Exact score values | `Assert.AreEqual(expected, actual)` |
| Score within range | `Assert.IsInRange(actual, low, high)` |
| Score above threshold | `Assert.IsGreaterThan(threshold, actual)` |
| Score capped at max | `Assert.IsLessThan(upperBound, actual)` |
| Invalid input throws | `Assert.ThrowsExactly<ArgumentOutOfRangeException>(...)` |
| Grade label | `Assert.AreEqual("A", grade)` with `[DataRow]` for boundaries |

Here's a complete test class using these:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc;

    public ScoreCalculatorTests()
    {
        _calc = new ScoreCalculator();
    }

    // --- CalculatePercentage: exact values & boundaries ---

    [TestMethod]
    [DataRow(10, 10, 100.0, DisplayName = "Perfect score")]
    [DataRow(0, 10, 0.0, DisplayName = "Zero correct")]
    [DataRow(1, 1, 100.0, DisplayName = "Minimum total")]
    [DataRow(7, 10, 70.0, DisplayName = "Typical score")]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calc.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calc.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade: boundary values at each grade threshold ---

    [TestMethod]
    [DataRow(100.0, "A", DisplayName = "100 → A")]
    [DataRow(90.0, "A", DisplayName = "90 boundary → A")]
    [DataRow(89.9, "B", DisplayName = "Just below 90 → B")]
    [DataRow(80.0, "B", DisplayName = "80 boundary → B")]
    [DataRow(79.9, "C", DisplayName = "Just below 80 → C")]
    [DataRow(70.0, "C", DisplayName = "70 boundary → C")]
    [DataRow(69.9, "D", DisplayName = "Just below 70 → D")]
    [DataRow(60.0, "D", DisplayName = "60 boundary → D")]
    [DataRow(59.9, "F", DisplayName = "Just below 60 → F")]
    [DataRow(0.0, "F", DisplayName = "Zero → F")]
    public void GetGrade_AtBoundary_ReturnsExpectedGrade(
        double percentage, string expected)
    {
        var grade = _calc.GetGrade(percentage);
        Assert.AreEqual(expected, grade);
    }

    // --- NormalizeScore: range capping & boundaries ---

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150.0, 100.0);

        // Verify it doesn't exceed the cap
        Assert.IsLessThan(101.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calc.NormalizeScore(50.0, 100.0);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        var result = _calc.NormalizeScore(0.0, 100.0);
        Assert.AreEqual(0.0, result);
        Assert.IsGreaterThan(-1.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50.0, 0.0));
    }
}
```

**Key patterns used:**

- **`Assert.IsInRange`** — validates a score stays within `[0, 100]`
- **`Assert.IsGreaterThan` / `Assert.IsLessThan`** — checks threshold boundaries (note: first arg is the bound, second is actual)
- **`Assert.ThrowsExactly<T>`** — verifies exact exception type for invalid inputs
- **`[DataRow]` with `DisplayName`** — parameterizes grade boundary tests at each threshold (90, 80, 70, 60) and just below
- **`Assert.AreEqual(expected, actual)`** — expected always first for clear failure messages
